// Simple local auth — no backend needed
// In production, replace with real auth (Firebase, Supabase, etc.)

const USERS_KEY = 'tm_users';
const SESSION_KEY = 'tm_session';

function getUsers() {
  try { return JSON.parse(localStorage.getItem(USERS_KEY) || '[]'); }
  catch { return []; }
}

function saveUsers(users) {
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
}

export function register(name, email, password) {
  const users = getUsers();
  if (users.find(u => u.email === email)) return { ok: false, error: 'Email already registered' };
  const user = { id: Date.now(), name, email, password, avatar: name.slice(0,2).toUpperCase(), createdAt: new Date().toISOString() };
  saveUsers([...users, user]);
  const session = { id: user.id, name: user.name, email: user.email, avatar: user.avatar };
  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  return { ok: true, user: session };
}

export function login(email, password) {
  const users = getUsers();
  const user  = users.find(u => u.email === email && u.password === password);
  if (!user) return { ok: false, error: 'Invalid email or password' };
  const session = { id: user.id, name: user.name, email: user.email, avatar: user.avatar };
  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  return { ok: true, user: session };
}

export function logout() {
  localStorage.removeItem(SESSION_KEY);
}

export function getSession() {
  try { return JSON.parse(localStorage.getItem(SESSION_KEY)); }
  catch { return null; }
}
